package com.maum.backend.service

import com.maum.backend.dto.FollowCountDto
import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.FollowNotFoundException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.repository.follow.FollowRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
class UserService(
    private val followRepository: FollowRepository,
) {

    /**
     * 팔로우 등록
     * @throws SelfFollowException 자기 자신을 팔로우하려는 경우
     * @throws AlreadyFollowingException 이미 팔로우한 경우
     */
    @Transactional
    fun follow(followerId: String, followeeId: String) {
        if (followerId == followeeId) {
            throw SelfFollowException(followerId)
        }
        if (followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw AlreadyFollowingException(followerId, followeeId)
        }
        followRepository.save(
            FollowEntity(followerId = followerId, followeeId = followeeId)
        )
    }

    /**
     * 언팔로우
     * @throws FollowNotFoundException 팔로우 관계가 없는 경우
     */
    @Transactional
    fun unfollow(followerId: String, followeeId: String) {
        if (!followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw FollowNotFoundException(followerId, followeeId)
        }
        followRepository.deleteByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    /**
     * 팔로우 여부 확인
     */
    @Transactional(readOnly = true)
    fun isFollowing(followerId: String, followeeId: String): Boolean {
        return followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    /**
     * 팔로워/팔로잉 수 조회
     */
    @Transactional(readOnly = true)
    fun getFollowCount(userId: String): FollowCountDto {
        return FollowCountDto(
            userId = userId,
            followerCount = followRepository.countByFolloweeId(userId),
            followingCount = followRepository.countByFollowerId(userId),
        )
    }
}
```

