import com.maum.backend.dto.FollowCountDto
import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.FollowNotFoundException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.repository.follow.FollowRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.never
import org.mockito.Mockito.verify
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import org.mockito.kotlin.whenever

@ExtendWith(MockitoExtension::class)
class UserServiceTest {

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // ===== follow() =====

    @Test
    fun `should follow successfully when valid follower and followee`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(false)
        whenever(followRepository.save(any<FollowEntity>()))
            .thenAnswer { it.arguments[0] }

        // when
        userService.follow(followerId, followeeId)

        // then
        verify(followRepository).existsByFollowerIdAndFolloweeId(followerId, followeeId)
        verify(followRepository).save(any<FollowEntity>())
    }

    @Test
    fun `should throw SelfFollowException when follower tries to follow themselves`() {
        // given
        val userId = "user-A"

        // when & then
        val exception = assertThrows<SelfFollowException> {
            userService.follow(userId, userId)
        }
        assertThat(exception.userId).isEqualTo(userId)
        // 자기 자신 팔로우 시 DB 조회/저장 없어야 함
        verify(followRepository, never()).existsByFollowerIdAndFolloweeId(any(), any())
        verify(followRepository, never()).save(any<FollowEntity>())
    }

    @Test
    fun `should throw AlreadyFollowingException when already following`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(true)

        // when & then
        val exception = assertThrows<AlreadyFollowingException> {
            userService.follow(followerId, followeeId)
        }
        assertThat(exception.followerId).isEqualTo(followerId)
        assertThat(exception.followeeId).isEqualTo(followeeId)
        // 중복 팔로우 시 저장 시도 없어야 함
        verify(followRepository, never()).save(any<FollowEntity>())
    }

    @Test
    fun `should save FollowEntity with correct follower and followee ids`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(false)

        var savedEntity: FollowEntity? = null
        whenever(followRepository.save(any<FollowEntity>())).thenAnswer { invocation ->
            savedEntity = invocation.arguments[0] as FollowEntity
            savedEntity
        }

        // when
        userService.follow(followerId, followeeId)

        // then
        assertThat(savedEntity).isNotNull
        assertThat(savedEntity!!.followerId).isEqualTo(followerId)
        assertThat(savedEntity!!.followeeId).isEqualTo(followeeId)
    }

    // ===== unfollow() =====

    @Test
    fun `should unfollow successfully when follow relationship exists`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(true)

        // when
        userService.unfollow(followerId, followeeId)

        // then
        verify(followRepository).deleteByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    @Test
    fun `should throw FollowNotFoundException when trying to unfollow non-existing relationship`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(false)

        // when & then
        val exception = assertThrows<FollowNotFoundException> {
            userService.unfollow(followerId, followeeId)
        }
        assertThat(exception.followerId).isEqualTo(followerId)
        assertThat(exception.followeeId).isEqualTo(followeeId)
        // 팔로우 관계 없으면 삭제 시도 없어야 함
        verify(followRepository, never()).deleteByFollowerIdAndFolloweeId(any(), any())
    }

    // ===== isFollowing() =====

    @Test
    fun `should return true when following relationship exists`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(true)

        // when
        val result = userService.isFollowing(followerId, followeeId)

        // then
        assertThat(result).isTrue()
        verify(followRepository).existsByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    @Test
    fun `should return false when following relationship does not exist`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(false)

        // when
        val result = userService.isFollowing(followerId, followeeId)

        // then
        assertThat(result).isFalse()
    }

    @Test
    fun `should return false when checking self-follow status`() {
        // given
        val userId = "user-A"
        whenever(followRepository.existsByFollowerIdAndFolloweeId(userId, userId))
            .thenReturn(false)

        // when
        val result = userService.isFollowing(userId, userId)

        // then
        assertThat(result).isFalse()
    }

    // ===== getFollowCount() =====

    @Test
    fun `should return correct follow counts for a user`() {
        // given
        val userId = "user-A"
        whenever(followRepository.countByFolloweeId(userId)).thenReturn(10L)
        whenever(followRepository.countByFollowerId(userId)).thenReturn(5L)

        // when
